import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { HttpClient } from '@angular/common/http';

@Component({
  selector: 'app-investor-dashboard',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './investor-dashboard.component.html',
  styleUrls: ['./investor-dashboard.component.css']
})
export class InvestorDashboardComponent implements OnInit {
  myInvestments: any[] = [];
  stats: any = {
    totalInvested: 0,
    totalM2Owned: 0,
    estimatedValuation: 0,
    projectsCount: 0
  };
  isLoading: boolean = true;

  constructor(private http: HttpClient) {}

  ngOnInit() {
    this.loadPortfolio();
  }

  loadPortfolio() {
    // Mocking the portfolio for the prototype
    setTimeout(() => {
      this.myInvestments = [
        {
          id: 'inv-1',
          location: 'Kribi - Chutes de la Lobé',
          amountInvested: 1000000,
          m2Equivalent: 75,
          currentStep: 'FIELD_SURVEY',
          progress: 40,
          status: 'ACTIVE',
          estimatedGain: 450000,
          imageUrl: 'https://images.unsplash.com/photo-1500382017468-9049fee74a62?auto=format&fit=crop&w=400'
        },
        {
          id: 'inv-2',
          location: 'Yaoundé - Febe Village',
          amountInvested: 500000,
          m2Equivalent: 30,
          currentStep: 'DOSSIER_SUBMITTED',
          progress: 20,
          status: 'ACTIVE',
          estimatedGain: 175000,
          imageUrl: 'https://images.unsplash.com/photo-1464822759023-fed622ff2c3b?auto=format&fit=crop&w=400'
        }
      ];

      this.calculateStats();
      this.isLoading = false;
    }, 1000);
  }

  calculateStats() {
    this.stats.totalInvested = this.myInvestments.reduce((acc, inv) => acc + inv.amountInvested, 0);
    this.stats.totalM2Owned = this.myInvestments.reduce((acc, inv) => acc + inv.m2Equivalent, 0);
    this.stats.projectsCount = this.myInvestments.length;
    this.stats.estimatedValuation = this.stats.totalInvested + this.myInvestments.reduce((acc, inv) => acc + inv.estimatedGain, 0);
  }

  formatCurrency(amount: number): string {
    return new Intl.NumberFormat('fr-CM', { style: 'currency', currency: 'XAF' }).format(amount);
  }

  getStepLabel(step: string): string {
    const steps: any = {
      'DOSSIER_SUBMITTED': 'Dossier déposé',
      'FIELD_SURVEY': 'Bornage en cours',
      'PUBLIC_NOTICE': 'Publication Avis',
      'FINAL_REVIEW': 'Examen Final',
      'COMPLETED': 'Titre Signé'
    };
    return steps[step] || step;
  }
}
<div class="investor-dashboard">
  <div class="header-section" style="margin-bottom: 2rem;">
    <h2>Mon Portefeuille maTerre</h2>
    <p>Suivez la croissance de votre patrimoine foncier au Cameroun.</p>
  </div>

  <!-- Portfolio Stats -->
  <div class="stats-grid" style="display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 1.5rem; margin-bottom: 3rem;">
    <div class="card" style="border-left: 5px solid var(--mt-green); background: #f1f8e9;">
      <p style="margin: 0; font-size: 0.8rem; color: #666;">SURFACE TOTALE DÉTENUE</p>
      <p style="margin: 5px 0 0 0; font-size: 2rem; font-weight: bold; color: var(--mt-green);">{{ stats.totalM2Owned }} m²</p>
    </div>
    <div class="card" style="border-left: 5px solid var(--mt-gold); background: #fffde7;">
      <p style="margin: 0; font-size: 0.8rem; color: #666;">CAPITAL TOTAL INVESTI</p>
      <p style="margin: 5px 0 0 0; font-size: 1.5rem; font-weight: bold;">{{ formatCurrency(stats.totalInvested) }}</p>
    </div>
    <div class="card" style="border-left: 5px solid var(--mt-green); background: var(--mt-green); color: white;">
      <p style="margin: 0; font-size: 0.8rem; color: rgba(255,255,255,0.8);">VALORISATION ESTIMÉE (APRÈS TITRAGE)</p>
      <p style="margin: 5px 0 0 0; font-size: 1.5rem; font-weight: bold;">{{ formatCurrency(stats.estimatedValuation) }}</p>
      <p style="margin: 5px 0 0 0; font-size: 0.8rem; font-weight: bold;">📈 +{{ ((stats.estimatedValuation - stats.totalInvested) / stats.totalInvested * 100) | number:'1.0-0' }}%</p>
    </div>
  </div>

  <h3>Mes Co-Investissements Actifs</h3>
  <div *ngIf="isLoading" style="text-align: center; padding: 2rem;">Chargement du portefeuille...</div>

  <div *ngIf="!isLoading" style="display: grid; gap: 1.5rem;">
    <div *ngFor="let inv of myInvestments" class="card" style="display: flex; gap: 20px; padding: 0; overflow: hidden; align-items: stretch;">
      <img [src]="inv.imageUrl" style="width: 150px; object-fit: cover;">
      
      <div style="flex: 1; padding: 1.5rem;">
        <div style="display: flex; justify-content: space-between; align-items: flex-start;">
          <div>
            <h4 style="margin: 0; color: var(--mt-green);">{{ inv.location }}</h4>
            <p style="margin: 5px 0 0 0; font-size: 0.85rem; color: #666;">Investissement: <strong>{{ formatCurrency(inv.amountInvested) }}</strong> → <strong>{{ inv.m2Equivalent }} m²</strong></p>
          </div>
          <span style="background: #e8f5e9; color: var(--mt-green); padding: 4px 10px; border-radius: 4px; font-size: 0.7rem; font-weight: bold;">{{ inv.status }}</span>
        </div>

        <!-- Tracking Progress -->
        <div style="margin-top: 1.5rem;">
          <div style="display: flex; justify-content: space-between; font-size: 0.75rem; margin-bottom: 5px;">
            <span>Étape actuelle: <strong>{{ getStepLabel(inv.currentStep) }}</strong></span>
            <span>{{ inv.progress }}%</span>
          </div>
          <div style="width: 100%; height: 6px; background: #eee; border-radius: 3px; overflow: hidden;">
            <div [style.width]="inv.progress + '%'" style="height: 100%; background: var(--mt-gold);"></div>
          </div>
        </div>

        <div style="margin-top: 1rem; display: flex; justify-content: space-between; align-items: center;">
          <p style="margin: 0; font-size: 0.75rem; color: #888;">Géré par maTerre Partner Notary 🛡️</p>
          <button class="btn-primary" style="padding: 5px 15px; font-size: 0.75rem; background: white; color: var(--mt-green); border: 1px solid var(--mt-green);">Voir Détails</button>
        </div>
      </div>
    </div>
  </div>

  <!-- CTAs -->
  <div style="margin-top: 3rem; text-align: center;">
    <button class="btn-primary" style="padding: 15px 30px; font-size: 1.1rem;">Explorer de nouvelles opportunités</button>
  </div>
</div>
